"use strict";parserFactory.register("quanben5.io",()=>new Quanben5Parser);class Quanben5Parser extends Parser{constructor(){super()}async getChapterUrls(e){let r=e.querySelector("ul.list");return util.hyperlinksToChapterList(r)}findContent(e){return e.querySelector("#content")}extractTitleImpl(e){return e.querySelector("h3")}extractAuthor(e){let r=e.querySelector("span.author");return r?.textContent??super.extractAuthor(e)}extractLanguage(){return"zh"}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.pic_txt_list")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("p.description")]}}